local LDefenceWarBaseCtrl = LXImport(".LDefenceWarBaseCtrl")

---@class LDefenceWarHudCtrl:LDefenceWarBaseCtrl
local LDefenceWarHudCtrl  = LxClass("LDefenceWarHudCtrl", LDefenceWarBaseCtrl)
-----------------------------------------------------------------

local typeOfTextMesh      = typeof(CS.TextMeshPro)
local Tweening            = DG.Tweening
local Color               = Color
local Vector3             = Vector3

-----------------------------------------------------------------
function LDefenceWarHudCtrl:LDefenceWarHudCtrl()
    self._index = 0
    self._seqMap = {}
    self._objDelayMap = {}
    self._cacheList = {}
end

-- 销毁
function LDefenceWarHudCtrl:OnDestroy()
    for k, tab in pairs(self._seqMap) do
        if tab.seq then
            tab.seq:Kill()
        end
    end
    self._seqMap = {}

    CS.DestroyObject(self._poolTrans.gameObject)
    CS.DestroyObject(self._enemyParent.gameObject)
end

-- 初始化
function LDefenceWarHudCtrl:Init()
    local root        = self:GetMap():GetMapTrans()
    local layerHud    = CS.FindTrans(root, "LayerRoot/LayerHud")

    self._poolTrans   = CS.NewObject("Pool", layerHud)
    self._enemyParent = CS.NewObject("Enemy", layerHud)

    local trans       = CS.FindTrans(root, "LayerRoot/ObjRoot/Enemy")
    self._nodeObj     = trans.gameObject
end

-- Update
function LDefenceWarHudCtrl:Update()

end

-- 显示飘字
function LDefenceWarHudCtrl:ShowHud(pos, num, delayTime, objIndex)
    self._index   = self._index + 1
    local index   = self._index

    local obj     = self:PopObj()
    local trans   = obj.transform
    local hurtTxt = obj.txt
    trans:SetParent(self._enemyParent, false)

    hurtTxt.text = num

    pos.x = pos.x + 0.3
    local color = hurtTxt.color
    color.a = 0
    hurtTxt.color = color
    trans.position = pos
    trans.localScale = Vector3(0.1, 0.1, 0.1)

    local tw1 = YXTween.TweenFloat(0, 1, 0.3, function(ival)
        hurtTxt.color = Color(color.r, color.g, color.b, ival)
    end)
    local tw2 = trans:DOScale(1.2, 0.3)
    local tw22 = trans:DOScale(1, 0.2)
    local tw3 = trans:DOMoveY(pos.y + 0.5, 1.5)
    local tw4 = YXTween.TweenFloat(1, 0, 1, function(ival)
        hurtTxt.color = Color(color.r, color.g, color.b, ival)
    end)

    delayTime = delayTime or 0


    local seq = Tweening.DOTween.Sequence()
    seq:Insert(delayTime, tw1)
    seq:Insert(delayTime, tw2)
    seq:Insert(delayTime + 0.3, tw22)
    seq:Insert(delayTime + 0.3, tw3)
    seq:Insert(delayTime + 1, tw4)
    seq:Play()
    seq:OnComplete(function()
        self._seqMap[index].seq = nil
        self:RecycleObj(obj)
    end)

    self._seqMap[index] = { seq = seq }
end

-- 获取同一个对象的延迟时间
function LDefenceWarHudCtrl:GetObjDelayTime(objIndex)
    local list = self._objDelayMap[objIndex]
    if not list then
        list = {}
        table.insert(list, os.clock())
        self._objDelayMap[objIndex] = list
    else
        local lastTime = list[#list]
    end
end

-- 弹出一个对象
function LDefenceWarHudCtrl:PopObj()
    local data = table.remove(self._cacheList)
    if not data then
        data = self:CreateObj()
    end
    return data
end

-- 回收一个对象
function LDefenceWarHudCtrl:RecycleObj(data)
    data.transform:SetParent(self._poolTrans, false)
    table.insert(self._cacheList, data)
end

-- 创建一个对象
function LDefenceWarHudCtrl:CreateObj()
    local obj       = self._nodeObj
    local data      = {}

    data.gameObject = LxUnity.InstantObject(obj)
    data.transform  = data.gameObject.transform
    data.txt        = data.transform:GetComponent(typeOfTextMesh)

    local mt        = {}
    mt.__index      = data
    mt.__newindex   = function(self, key, value)
        error("此表，只读")
    end

    setmetatable(data, mt)
    return data
end

return LDefenceWarHudCtrl
